 			totalAccepted: attempts.filter((a) => a.accepted).length,
 			totalRejected: attempts.filter((a) => !a.accepted).length,
 			cumulativeImprovement: attempts.filter((a) => a.accepted).reduce((sum, a) => sum + (a.scoreDelta ?? 0), 0),
 		};
 		return archive;
